		name := getAttributeValue(n, "name")
		content := getAttributeValue(n, "content")

		if strings.ToLower(name) == "description" && preview.Description == "" {
			preview.Description = content
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		extractPreview(c, preview)
	}
}

// getAttributeValue retrieves the value of an attribute from a node
func getAttributeValue(n *html.Node, attrName string) string {
	for _, attr := range n.Attr {
		if strings.ToLower(attr.Key) == strings.ToLower(attrName) {
			return attr.Val
		}
	}
	return ""
}

