	"crypto/tls"
	"fmt"
	"io"
	"net/http"
	"time"

	"github.com/labstack/echo/v4"
	"golang.org/x/net/html"
)

// Request struct for JSON input
type URLRequest struct {
	URL string `json:"url"`
}

// Response struct for JSON output
type URLPreview struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid JSON body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	client := &http.Client{
		Timeout: 3 * time.Second,
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{
				InsecureSkipVerify: true,
			},
		},
	}

	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": fmt.Sprintf("unexpected status code: %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to read response body"})
	}

	title, description := parseHTML(body)

	result := URLPreview{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, result)
}

func parseHTML(data []byte) (title, description string) {
	z := html.NewTokenizer(bytes.NewReader(data))
	inTitle := false
	inMeta := false

	for {
		tt := z.Next()

		switch tt {
		case html.ErrorToken:
			return title, description

		case html.StartTagToken, html.SelfClosingTagToken:
			t := z.Token()
			if t.Data == "title" {
				inTitle = true
			} else if t.Data == "meta" {
				for _, attr := range t.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						inMeta = true
					} else if inMeta && attr.Key == "content" {
						description = attr.Val
						inMeta = false
					}
				}
			}

		case html.TextToken:
			if inTitle {
				title = z.Token().Data
				inTitle = false
			}

		case html.EndTagToken:
			t := z.Token()
			if t.Data == "title" {
				inTitle = false
			}
		}
	}
}

