	description := extractMetaContent(htmlStr, "description")
	if description == "" {
		description = extractMetaContent(htmlStr, "og:description")
	}
	if description == "" {
		description = "No description found"
	}

	return title, description
}

func extractTagContent(html, openTag, closeTag string) string {
	start := strings.Index(html, openTag)
	if start == -1 {
		return ""
	}
	start += len(openTag)
	end := strings.Index(html[start:], closeTag)
	if end == -1 {
		return ""
	}
	return strings.TrimSpace(html[start : start+end])
}

func extractMetaContent(html, name string) string {
	// Normalize name to lowercase for comparison
	nameLower := strings.ToLower(name)
	_ = nameLower // Avoid unused variable warning

	// Match meta tags with name or property attribute
	re := regexp.MustCompile(`(?i)<meta[^>]*?content=["']([^"']*)["'][^>]*?name=["'][^"']*?` + regexp.QuoteMeta(name) + `["'][^>]*>|<meta[^>]*?content=["']([^"']*)["'][^>]*?property=["'][^"']*?` + regexp.QuoteMeta(name) + `["'][^>]*>`)
