}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	html := strings.ToLower(string(htmlContent))

	// Extract title
	titleRegex := regexp.MustCompile(`<title[^>]*>([^<]*)</title>`)
	titleMatches := titleRegex.FindStringSubmatch(html)
	title := ""
	if len(titleMatches) > 1 {
