	description := ""
	descRegex := regexp.MustCompile(`<meta[^>]+name=["']description["'][^>]+content=["']([^"']*)["']`)
	descMatches := descRegex.FindStringSubmatch(html)
	if len(descMatches) > 1 {
		description = descMatches[1]
	}

