	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// isPrivateIP checks if a hostname resolves to a private IP address
func isPrivateIP(hostname string) bool {
	ip := net.ParseIP(hostname)
	if ip == nil {
		// Try to resolve hostname
		ips, err := net.LookupIP(hostname)
		if err != nil {
			return true // Fail closed
		}
		for _, ip := range ips {
			if isPrivateIPAddr(ip) {
				return true
			}
		}
		return false
	}
	return isPrivateIPAddr(ip)
}

// isPrivateIPAddr checks if an IP address is private
func isPrivateIPAddr(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast() {
		return true
	}

	// Check for IPv4 private addresses
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || // 10.0.0.0/8
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] < 32) || // 172.16.0.0/12
			(ip4[0] == 192 && ip4[1] == 168) // 192.168.0.0/16
	}

	// Check for IPv6 local addresses
	if ip.To16() != nil {
		return ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast()
	}

	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	htmlStr := strings.ToLower(string(htmlContent))

	// Extract title
	title := extractTagContent(htmlStr, "<title>", "</title>")
	if title == "" {
		// Try meta title
		title = extractMetaContent(htmlStr, "title")
	}

	// Extract description
	description := extractMetaContent(htmlStr, "description")
	if description == "" {
		description = extractMetaContent(htmlStr, "og:description")
	}

	return strings.TrimSpace(title), strings.TrimSpace(description)
}

func extractTagContent(html, start, end string) string {
	startIdx := strings.Index(html, start)
	if startIdx == -1 {
		return ""
	}
	startIdx += len(start)
	endIdx := strings.Index(html[startIdx:], end)
	if endIdx == -1 {
		return ""
	}
	return strings.TrimSpace(html[startIdx : startIdx+endIdx])
}

func extractMetaContent(html, name string) string {
	// Match meta tag with name or property attribute
	patterns := []string{
		`<meta[^>]+name=["']` + name + `["'][^>]+content=["']([^"']*)["']`,
		`<meta[^>]+content=["']([^"']*)["'][^>]+name=["']` + name + `["']`,
		`<meta[^>]+property=["']og:` + name + `["'][^>]+content=["']([^"']*)["']`,
		`<meta[^>]+content=["']([^"']*)["'][^>]+property=["']og:` + name + `["']`,
	}

	for _, pattern := range patterns {
		re := regexp.MustCompile(pattern)
		match := re.FindStringSubmatch(html)
		if len(match) > 1 {
			return match[1]
		}
	}
	return ""
}

