		URL:    parsedURL,
		Header: map[string][]string{
			"User-Agent": {"Mozilla/5.0 (compatible; URLPreviewBot/1.0)"},
		},
	})
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	// Convert to string for regex matching
	htmlStr := string(htmlContent)

	// Extract title
	title := extractTagContent(htmlStr, "<title>", "</title>")
	if title != "" {
		title = strings.TrimSpace(title)
		title = strings.ReplaceAll(title, "\n", " ")
	}

	// Extract description meta tag
	description := extractMetaContent(htmlStr, "description")
	if description == "" {
		description = extractMetaContent(htmlStr, "og:description")
	}

	return title, description
}

func extractTagContent(html, startTag, endTag string) string {
	start := strings.Index(html, startTag)
	if start == -1 {
		return ""
	}
	start += len(startTag)
	end := strings.Index(html[start:], endTag)
	if end == -1 {
		return ""
	}
	return html[start : start+end]
}

func extractMetaContent(html, name string) string {
	// Case-insensitive search for meta name="description"
	regex := regexp.MustCompile(`(?i)<meta[^>]*name=["']` + regexp.QuoteMeta(name) + `["'][^>]*content=["']([^"']*)["']`)
	match := regex.FindStringSubmatch(html)
	if len(match) > 1 {
		return strings.TrimSpace(match[1])
	}

	// Fallback: search for property attribute for og:tags
	regex = regexp.MustCompile(`(?i)<meta[^>]*property=["']` + regexp.QuoteMeta("og:"+name) + `["'][^>]*content=["']([^"']*)["']`)
	match = regex.FindStringSubmatch(html)
	if len(match) > 1 {
		return strings.TrimSpace(match[1])
	}

	return ""
}

